const report = $('Get Autonomy Report').first().json;
const backlog = $('Get Full Backlog').first().json;
const today = new Date().toISOString().split('T')[0];

const top3 = (report.top_opportunities || []).slice(0, 3);
const topList = top3.map((o, i) => `${i+1}. **${o.title}** (ROI: ${o.roi_score || 'N/A'} min/wk)\n   ${o.description || ''}`).join('\n\n') || 'No new opportunities this week.';

const backlogItems = (backlog.opportunities || []);
const totalROI = backlogItems.reduce((sum, o) => sum + (parseFloat(o.roi_score) || 0), 0);
const implemented = backlogItems.filter(o => o.status === 'implemented').length;
const pending = backlogItems.filter(o => o.status === 'backlog').length;

const md = `# HCI AI — Weekly Automation Opportunities\n**${today}**\n\n## Top 3 This Week\n\n${topList}\n\n## Backlog Summary\n- Total opportunities tracked: ${backlogItems.length}\n- Implemented: ${implemented}\n- Pending: ${pending}\n- Cumulative ROI potential: ${Math.round(totalROI)} min/wk (${Math.round(totalROI/60 * 52)} hrs/yr)\n\n---\n*Generated: ${new Date().toISOString()} by AUTO-WEEKLY-REPORT*`;

const pushMsg = top3.length > 0
  ? `Top opportunity: ${top3[0].title} (${top3[0].roi_score || '?'} min/wk ROI)`
  : 'No new automation opportunities detected this week';

return [{ json: { md, pushMsg, top3_count: top3.length, total_roi: Math.round(totalROI), filename: `reports/sprint/auto-opps-${today}.md` } }];
